// Add year, employee count, email, slug to each
const fullSuppliers = suppliers.map((s, i) => ({
  ...s,
  yearEstablished: randomBetween(1985, 2018),
  employeeCount: randomBetween(50, 15000),
  contactEmail: `info@${s.companyName.toLowerCase().replace(/[^a-z0-9]/g, "").slice(0, 20)}.com`,
  slug: slugify(s.companyName, i + 1),
  rating: s.rating ?? randomFloat(3.5, 5.0),
  verified: s.verified ?? (Math.random() > 0.4),
  countryCode: s.countryCode ?? "XX",
  city: (s as any).city ?? "N/A",
  region: null,
  subIndustry: null,
  contactPhone: null,
  website: null,
  certifications: null,
  annualRevenue: null,
  responseTime: null,
  minOrderValue: null,
  currency: "USD",
  paymentTerms: null,
  exportMarkets: null,
  logoUrl: null,
  dataSource: "SmartSeek Seed",
  registryUrl: null,
  registryId: null,
  sicCode: null,
  contactVerified: false,
  reviewCount: randomBetween(0, 120),
}));

async function main() {
  console.log(`Seeding ${fullSuppliers.length} suppliers...`);
  let inserted = 0;
  let skipped = 0;
  for (const s of fullSuppliers) {
    try {
      await prisma.supplier.upsert({
        where: { slug: s.slug },
        update: {},
        create: s,
      });
      inserted++;
    } catch (e: any) {
      console.warn(`Skipped ${s.companyName}: ${e?.message}`);
      skipped++;
    }
  }
  console.log(`Done. Inserted/updated: ${inserted}, skipped: ${skipped}`);
}

main().catch(console.error).finally(() => prisma.$disconnect());
